  ('elementary-7fec267e-moex-00638', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-01c5eaab', 'sub-elementary-7fec267e-05', NULL, 'single_choice', '下列選項「」中的詞語，何者運用最不恰當？', '["「春去秋來」，歲月不待", "春天是「鳥語花香」的季節", "他心性放蕩，成日「尋花問柳」", "下課後，老師如「雨後春筍」般湧出來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
