  ('elementary-7fec267e-moex-00642', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-01c5eaab', 'sub-elementary-7fec267e-05', NULL, 'single_choice', '「這些機器不是阿公以前工廠裡的織布機，但機器運轉的聲音十分相似，那聲音幾乎要讓我以為， 阿公就在這裡，只要我願意等，他就會從樓上走下來。想到這裡，我趕緊走到屋外，深吸一口氣， 緩和情緒，怕自己在不熟識的人面前，忍不住哭了出來。」 上文主要是描述什麼情感？', '["對不熟識人的害羞", "對親人的幻覺想像", "對阿公的思念之情", "對個人情緒的控制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00643', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-01c5eaab', 'sub-elementary-7fec267e-05', NULL, 'single_choice', '「一國的民族文化能否保持活力，仰賴的無非是與其他文化互動，畢竟專業知能與創造力都奠基於 不同類型的知識與觀點的對話及互補。」依此觀點，下列何種政策對增進民族文化的活力最無效益？', '["健全發展交換學生制度", "加強促進跨國科技研發", "立法獎勵國際人才移動", "嚴格規定交流學者資格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
